draw((0,0)--(0,4)--(4,4)--(4,0)--cycle);
draw(A--Ap--B--Bp--cycle,linetype("4 3"));
draw(A--(1,0));
draw(A--B);
draw((1,eps)--(1+eps,eps)--(1+eps,0));
label("$A$",A,N);
label("$B$",B,S);
label("$r$",(4,2.5),E);
label("$s$",(4,0.5),E);
label("$C$",(1,0),S);[/asy]

